import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, EventEmitter, HostListener, Input, Output, ViewEncapsulation, } from '@angular/core';
import { LucideAngularModule, X } from 'lucide-angular';
/**
 * Menu latéral hiérarchique avec sections + items.
 * Cf. décision J.3 : variant explicite, pas d'auto-switch responsive.
 */
let OriSideMenuComponent = class OriSideMenuComponent {
    constructor() {
        this.sections = [];
        this.variant = 'persistent';
        this.open = true;
        this.ariaLabel = 'Menu de navigation';
        this.openChange = new EventEmitter();
        this.XIcon = X;
    }
    get navClasses() {
        return ['ori-side-menu', this.variant === 'drawer' ? 'ori-side-menu--drawer' : null]
            .filter((c) => Boolean(c))
            .join(' ');
    }
    closeMenu() {
        this.open = false;
        this.openChange.emit(false);
    }
    onEscape() {
        if (this.variant === 'drawer' && this.open) {
            this.closeMenu();
        }
    }
    static { this.propDecorators = {
        sections: [{ type: Input }],
        variant: [{ type: Input }],
        open: [{ type: Input }],
        ariaLabel: [{ type: Input }],
        openChange: [{ type: Output }],
        onEscape: [{ type: HostListener, args: ['document:keydown.escape',] }]
    }; }
};
OriSideMenuComponent = __decorate([
    Component({
        selector: 'ori-side-menu',
        standalone: true,
        imports: [LucideAngularModule],
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    @if (variant === 'persistent' || open) {
      @if (variant === 'drawer') {
        <div class="ori-side-menu__overlay" (click)="closeMenu()" aria-hidden="true"></div>
      }
      <nav
        [attr.aria-label]="ariaLabel"
        [class]="navClasses"
      >
        @if (variant === 'drawer') {
          <button
            type="button"
            class="ori-side-menu__close"
            aria-label="Fermer le menu"
            (click)="closeMenu()"
          >
            <lucide-icon [img]="XIcon" [size]="18" aria-hidden="true"></lucide-icon>
          </button>
        }
        @for (section of sections; track $index) {
          <div class="ori-side-menu__section">
            @if (section.title) {
              <div class="ori-side-menu__section-title">{{ section.title }}</div>
            }
            <ul class="ori-side-menu__list">
              @for (item of section.items; track item.href) {
                <li>
                  <a
                    [href]="item.href"
                    class="ori-side-menu__link"
                    [attr.aria-current]="item.current ? 'page' : null"
                  >{{ item.label }}</a>
                </li>
              }
            </ul>
          </div>
        }
      </nav>
    }
  `,
    })
], OriSideMenuComponent);
export { OriSideMenuComponent };
